      modal.classList.remove("open");
      modal.setAttribute("aria-hidden", "true");
    }

    function toggleFaq(button) {
      button.closest(".faq-item").classList.toggle("open");
    }

    function dismissCookieBanner(value) {
      localStorage.setItem(COOKIE_PREF_KEY, value);
      document.getElementById("cookieBanner").classList.remove("visible");
    }

    async function submitForm(event) {
      event.preventDefault();
      const button = document.getElementById("submitBtn");
      const error = document.getElementById("formError");
      button.disabled = true;
      button.textContent = "Sending...";
      error.style.display = "none";
      const payload = {
        source_site: "bigbearengineering.com",
        source_page: "/",
        source_form: "homepage_contact_modal",
        full_name: document.getElementById("f-name").value.trim(),
        work_email: document.getElementById("f-email").value.trim(),
        company: document.getElementById("f-company").value.trim(),
        interest: document.getElementById("f-tier").value,
        message: document.getElementById("f-message").value.trim(),
        consent: document.getElementById("f-consent").checked,
        status: "new",
        owner: "",
        notes: ""
      };
      try {
        await fetch(CONTACT_FORM_ENDPOINT, { method: "POST", mode: "no-cors", headers: { "Content-Type": "application/json" }, body: JSON.stringify(payload) });
        document.getElementById("formContent").style.display = "none";
        document.getElementById("formSuccess").style.display = "block";
      } catch (submissionError) {
        button.disabled = false;
        button.textContent = "Send Request";
        error.textContent = "Submission failed. Check the Apps Script deployment URL and CORS/no-cors behavior.";
        error.style.display = "block";
      }
    }

    document.getElementById("contactModal").addEventListener("click", function (event) {
      if (event.target === this) closeModal();
    });
    document.addEventListener("keydown", function (event) {
      if (event.key === "Escape") closeModal();
    });
    if (!localStorage.getItem(COOKIE_PREF_KEY)) {
      document.getElementById("cookieBanner").classList.add("visible");
    }
